                    entity.QuotaID,
                    entity.Name,
                    entity.TableName,
                    entity.Email,
                    entity.IsFCD,
                    entity.IsOptimistic,
                    entity.XmlData
                };

            table.Rows.Add(rowData);
        }
    }
}
